+ *
+ * @see https://knowhere-org.slack.com/archives/C03EGR0M9AN/p1759381143908219
+ */
+export const isStagingOrProductionSingleTeam = (team: Team): boolean => {
+  return (
+    (EnvManager.isStg || EnvManager.isPrd) && team.teamType === TeamType.SINGLE
+  );
+};

